using UnityEngine;

/// <summary>
/// Entrega os drops de um inimigo (Enemy Creator — Etapa 4.3), conforme
/// <see cref="EnemyData.drops"/> (EnemyDropConfig).
///
/// Escuta EnemyController.OnStateChanged: quando o inimigo passa a Morto (ou
/// Desactivado, se "dropOnDeactivated"), entrega uma única vez:
///
/// - Sementes (Random entre seedsMin/seedsMax) via PlayerProgress.GiveSementes.
/// - Broto de Vida (probabilidade "lifeSproutChance") via GiveBrotosDeVida.
/// - Item especial via PlayerProgress.AddItem (respeita ItemData.maxQuantity e
///   regista em collectedSpecialItemIds se "savedAsCollected"), sujeito a:
///   - condição de variável global ("requiredBoolVariable" — ex: missão activa);
///   - drop único ("specialDropOnlyOnce" ou ItemData.dropsOnlyOnce): se o item
///     já estiver registado como recolhido, não volta a dropar (persiste mesmo
///     após reentrar na área — liga à Etapa 7.3).
///
/// <see cref="ResetDrops"/> permite ao respawn (Etapa 7.3) rearmar os drops
/// comuns (o drop único continua bloqueado pelo registo no PlayerProgress).
/// </summary>
[DisallowMultipleComponent]
[RequireComponent(typeof(EnemyController))]
public class EnemyDropTable : MonoBehaviour
{
    private EnemyController _controller;
    private bool _dropped;

    /// <summary>Config de drops do EnemyData (null se "data" não estiver definido).</summary>
    public EnemyDropConfig Config => _controller != null && _controller.Data != null ? _controller.Data.drops : null;

    private void Awake()
    {
        _controller = GetComponent<EnemyController>();
    }

    private void OnEnable()
    {
        _controller.OnStateChanged += HandleStateChanged;
    }

    private void OnDisable()
    {
        _controller.OnStateChanged -= HandleStateChanged;
    }

    private void HandleStateChanged(EnemyState oldState, EnemyState newState)
    {
        var cfg = Config;
        if (cfg == null || _dropped) return;

        bool shouldDrop = newState == EnemyState.Morto ||
                          (newState == EnemyState.Desactivado && cfg.dropOnDeactivated);

        if (!shouldDrop) return;

        _dropped = true;
        GiveDrops(cfg);
    }

    private void GiveDrops(EnemyDropConfig cfg)
    {
        var progress = PlayerProgress.Instance;
        if (progress == null) return;

        // Sementes.
        int maxSeeds = Mathf.Max(cfg.seedsMin, cfg.seedsMax);
        if (maxSeeds > 0)
        {
            int seeds = Random.Range(cfg.seedsMin, maxSeeds + 1);
            if (seeds > 0) progress.GiveSementes(seeds);
        }

        // Broto de Vida — cura instantânea, NÃO vai para o inventário de recursos
        // (consistente com BrotoDeVidaPickup.GrantReward, que usa Heal() directamente).
        // Brotos comprados em loja chegam como ItemData e são usados manualmente.
        if (cfg.lifeSproutChance > 0f && Random.value < cfg.lifeSproutChance)
            progress.Heal(1);

        // Item especial.
        GiveSpecialItem(cfg, progress);
    }

    private void GiveSpecialItem(EnemyDropConfig cfg, PlayerProgress progress)
    {
        var item = cfg.specialItem;
        if (item == null) return;

        // Condição de variável global (ex: missão activa — Etapa 5.1).
        if (!string.IsNullOrEmpty(cfg.requiredBoolVariable))
        {
            var vars = GameVariables.Instance;
            bool value = vars != null && vars.GetBool(cfg.requiredBoolVariable);
            if (value != cfg.requiredBoolValue) return;
        }

        // Drop único: já recolhido = não repete.
        bool onlyOnce = cfg.specialDropOnlyOnce || item.dropsOnlyOnce;
        if (onlyOnce && progress.HasCollectedSpecialItem(item)) return;

        progress.AddItem(item, Mathf.Max(1, cfg.specialItemQuantity));

        // Garante o registo persistente do drop único mesmo que o ItemData não
        // tenha 'savedAsCollected' (AddItem já o faz quando tem).
        if (onlyOnce) progress.MarkSpecialItemCollected(item.itemId);
    }

    /// <summary>Rearma os drops (usado pelo respawn — Etapa 7.3). Drops únicos continuam bloqueados pelo registo em PlayerProgress.</summary>
    public void ResetDrops()
    {
        _dropped = false;
    }
}
